output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?cancer ?cancerLabel ?prevention ?preventionLabel WHERE {
  VALUES ?cancer {
    wd:Q17726 wd:Q34146 wd:Q33137 wd:Q14682
  }
  ?cancer rdfs:label ?cancerLabel .
  FILTER(LANG(?cancerLabel) = "en")
  ?cancer wdt:P2550 ?prevention .
  ?prevention rdfs:label ?preventionLabel .
  FILTER(LANG(?preventionLabel) = "en")
}

